    const n = nums.length;
    if (n === 0) {
        return -1;
    }

    // Step 1: Calculate Prefix Maximums (MaxPrefix[i] = max(nums[0..i]))
    const maxPrefix = new Array(n);
    let currentMax = -Infinity;
    for (let i = 0; i < n; i++) {
        if (nums[i] > currentMax) {
            currentMax = nums[i];
        }
        maxPrefix[i] = currentMax;
    }

    // Step 2: Calculate Suffix Minimums (MinSuffix[i] = min(nums[i..n-1]))
    const minSuffix = new Array(n);
    let currentMin = Infinity;
    for (let i = n - 1; i >= 0; i--) {
        if (nums[i] < currentMin) {
            currentMin = nums[i];
        }
        minSuffix[i] = currentMin;
    }

    // Step 3: Find the Smallest Stable Index
    for (let i = 0; i < n; i++) {
        // Instability = max(nums[0..i]) - min(nums[i..n-1])
        const instability = maxPrefix[i] - minSuffix[i];

        if (instability <= k) {
            return i;
        }
    }

    // If no stable index is found
    return -1;
}

